// Template function to find maximum
#include <iostream>
using namespace std;

template<typename T>
T maximum(T a, T b) {
    return (a > b) ? a : b;
}

int main() {
    int x = 5, y = 10;
    cout << "Max of ints: " << maximum(x, y) << endl;

    double p = 3.14, q = 2.71;
    cout << "Max of doubles: " << maximum(p, q) << endl;

    char c1 = 'A', c2 = 'Z';
    cout << "Max of chars: " << maximum(c1, c2) << endl;

    return 0;
}

// Generic Stack Class Template
#include <iostream>
#include <vector>
using namespace std;

template<typename T>
class Stack {
private:
    vector<T> elements;
public:
    void push(T const& elem) {
        elements.push_back(elem);
    }

    void pop() {
        if (elements.empty()) {
            cout << "Stack is empty!" << endl;
            return;
        }
        elements.pop_back();
    }

    T top() const {
        if (elements.empty()) {
            throw "Stack is empty!";
        }
        return elements.back();
    }

    bool isEmpty() const {
        return elements.empty();
    }

    void display() const {
        cout << "Stack (top to bottom): ";
        for (auto it = elements.rbegin(); it != elements.rend(); ++it) {
            cout << *it << " ";
        }
        cout << endl;
    }
};

int main() {
    Stack<int> intStack;
    intStack.push(10);
    intStack.push(20);
    intStack.push(30);
    intStack.display();
    cout << "Top: " << intStack.top() << endl;
    intStack.pop();
    intStack.display();

    Stack<string> strStack;
    strStack.push("Hello");
    strStack.push("World");
    strStack.display();

    return 0;
}

// Template Class with Specialization
#include <iostream>
using namespace std;

// Primary template with two type parameters
template<typename T1, typename T2>
class Pair {
private:
    T1 first;
    T2 second;
public:
    Pair(T1 a, T2 b) : first(a), second(b) {}

    void display() const {
        cout << "First: " << first << ", Second: " << second << endl;
    }

    T1 getFirst() const { return first; }
    T2 getSecond() const { return second; }
};

// Full template specialization for Pair<char, char>
template<>
class Pair<char, char> {
private:
    char first;
    char second;
public:
    Pair(char a, char b) : first(a), second(b) {}

    void display() const {
        cout << "First: '" << first << "' (ASCII: " << int(first) << ")" 
             << ", Second: '" << second << "' (ASCII: " << int(second) << ")" << endl;
    }

    char getFirst() const { return first; }
    char getSecond() const { return second; }
};

int main() {
    Pair<int, double> p1(10, 3.14);
    p1.display();

    Pair<string, int> p2("Age", 25);
    p2.display();

    Pair<char, char> p3('A', 'Z');
    p3.display();  // Uses specialized version with ASCII values

    return 0;
}

// Non-type Template Parameter
#include <iostream>
using namespace std;

// Template class with non-type parameter 'size'
template<typename T, int size>
class FixedArray {
private:
    T arr[size];
    int currentSize;
public:
    FixedArray() : currentSize(0) {}

    void add(T value) {
        if (currentSize < size) {
            arr[currentSize++] = value;
        } else {
            cout << "Array is full!" << endl;
        }
    }

    void display() const {
        cout << "Array elements: ";
        for (int i = 0; i < currentSize; i++) {
            cout << arr[i] << " ";
        }
        cout << endl;
    }

    int getSize() const { return currentSize; }
    int getCapacity() const { return size; }
};

int main() {
    // Array of 5 integers
    FixedArray<int, 5> intArr;
    intArr.add(10);
    intArr.add(20);
    intArr.add(30);
    intArr.display();
    cout << "Size: " << intArr.getSize() << ", Capacity: " << intArr.getCapacity() << endl;

    // Array of 3 strings
    FixedArray<string, 3> strArr;
    strArr.add("Hello");
    strArr.add("World");
    strArr.display();

    // Trying to add more than capacity
    strArr.add("Extra");

    return 0;
}
